const DealAhjAssocs = async (dealId) =>
{
  let GeneratorFunc = (resolve, reject) =>
  {
    let opts = 
    {
        "method": "GET",
        "hostname": "api.hubapi.com",
        "port": null,
        "path": "/crm/v4/objects/DEAL/" + dealId + "/associations/" + objectType + "?limit=500",
        "headers":
        {
            "accept": "application/json",
            "authorization": "Bearer " + process.env.photon_association_handler
        }
    };

    let req = http.request(opts, (res) =>
    {
        let chunks = [];

        res.on("data", (chunk) =>
        {
            chunks.push(chunk);
        });

        res.on("end", () =>
        {
            let body = Buffer.concat(chunks);
            body = body.toString();
            body = JSON.parse(body);
            body = body.results;
            resolve(body);
        });
    });

    req.end();
  };

  return new Promise(GeneratorFunc);
};

